#include<bits/stdc++.h>
using namespace std;
const int N = 5e6+5;
bool is[N];queue<int> q;
long long n,Q,a[5005],mn,dis[N];
void SPFA(){
    memset(dis,0x3f,sizeof(dis));
    q.push(0);is[0]=1;dis[0]=0;
    while(!q.empty()){
        int u=q.front();q.pop();is[u]=0;
        for(int i=1;i<=n;i++){
            if(a[i]==mn)continue;int v=(u+a[i])%mn;
            if(dis[u]+a[i]>=dis[v])continue;
            dis[v]=dis[u]+a[i];if(!is[v])is[v]=1,q.push(v);
        }
    }
    return;
}
int main(){
    cin>>n;mn=0x3f3f3f3f3f3f3f3f;
    for(int i=1;i<=n;i++){cin>>a[i];mn=min(mn,a[i]);}
    SPFA();cin>>Q;
    while(Q--){
        int x;cin>>x;
        if(dis[x%mn]<=x)cout<<"TAK\n";
        else cout<<"NIE\n";
    }
    return 0;
}
